# Allowlist of permitted domains for subscription endpoints
ALLOWED_DOMAINS = os.environ.get("ALLOWED_SUBSCRIPTION_DOMAINS", "").split(",")
ALLOWED_PROTOCOLS = {"https"}  # Only allow HTTPS, never HTTP

# Topic ARN should come from configuration, not user input
TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")

# Maximum endpoint URL length
MAX_URL_LENGTH = 2048


def validate_url(url: str) -> bool:
    """
    Validate that a URL is well-formed, uses HTTPS, and belongs to an allowed domain.
    """
    if not url or not isinstance(url, str):
        logger.warning("Empty or non-string URL provided.")
        return False

    if len(url) > MAX_URL_LENGTH:
        logger.warning("URL exceeds maximum allowed length.")
        return False

    # Strip whitespace
    url = url.strip()

    try:
        parsed = urlparse(url)
    except Exception:
        logger.warning("Failed to parse URL.")
        return False

    # Enforce HTTPS only
    if parsed.scheme not in ALLOWED_PROTOCOLS:
        logger.warning("URL scheme '%s' is not allowed. Only HTTPS is permitted.", parsed.scheme)
        return False

    # Ensure hostname is present
    if not parsed.hostname:
        logger.warning("URL has no hostname.")
        return False

    hostname = parsed.hostname.lower()

    # Reject IP addresses to prevent SSRF-style attacks
    ip_pattern = re.compile(
        r"^(\d{1,3}\.){3}\d{1,3}$"  # IPv4
        r"|^\[?[0-9a-fA-F:]+\]?$"    # IPv6
    )
    if ip_pattern.match(hostname):
        logger.warning("IP addresses are not allowed as subscription endpoints.")
        return False

    # Reject localhost and internal hostnames
    blocked_hostnames = {
        "localhost", "127.0.0.1", "0.0.0.0", "::1",
        "metadata.google.internal", "169.254.169.254",
    }
    if hostname in blocked_hostnames:
        logger.warning("Blocked hostname detected.")
        return False

    # Check against domain allowlist
    if not ALLOWED_DOMAINS or ALLOWED_DOMAINS == [""]:
        logger.error("No allowed domains configured. Set ALLOWED_SUBSCRIPTION_DOMAINS environment variable.")
        return False

    domain_allowed = False
    for allowed_domain in ALLOWED_DOMAINS:
        allowed_domain = allowed_domain.strip().lower()
        if not allowed_domain:
            continue
        # Exact match or subdomain match
        if hostname == allowed_domain or hostname.endswith("." + allowed_domain):
            domain_allowed = True
            break

    if not domain_allowed:
        logger.warning("Domain '%s' is not in the allowlist.", hostname)
        return False

    # Validate URL characters (reject control characters, etc.)
    if re.search(r"[\x00-\x1f\x7f]", url):
        logger.warning("URL contains invalid control characters.")
        return False

    return True


def validate_topic_arn(topic_arn: str) -> bool:
    """
    Validate that the topic ARN matches expected SNS ARN format.
    """
    if not topic_arn or not isinstance(topic_arn, str):
        return False

    arn_pattern = re.compile(
        r"^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$"
    )
    return bool(arn_pattern.match(topic_arn))


def create_sns_subscription(endpoint_url: str) -> dict:
    """
    Create an SNS subscription after validating the endpoint URL.
    """
    if not validate_topic_arn(TOPIC_ARN):
        logger.error("Invalid or missing SNS_TOPIC_ARN configuration.")
        raise ValueError("Invalid SNS topic ARN configuration.")

    # Validate the user-provided endpoint
    if not validate_url(endpoint_url):
        raise ValueError(
            f"Invalid endpoint URL. Must be HTTPS and belong to an allowed domain: "
            f"{', '.join(d for d in ALLOWED_DOMAINS if d.strip())}"
        )

    # Sanitize - strip whitespace
    sanitized_url = endpoint_url.strip()

    try:
        # Use HTTPS protocol only
        sns_client = boto3.client("sns")

        response = sns_client.subscribe(
            TopicArn=TOPIC_ARN,
            Protocol="https",
            Endpoint=sanitized_url,
            ReturnSubscriptionArn=True,
        )

        subscription_arn = response.get("SubscriptionArn", "pending confirmation")
        logger.info(
            "SNS subscription created successfully. SubscriptionArn: %s",
            subscription_arn,
        )

        return {
            "success": True,
            "subscription_arn": subscription_arn,
            "message": "Subscription created. Endpoint must confirm the subscription.",
        }

    except ClientError as e:
        error_code = e.response.get("Error", {}).get("Code", "Unknown")
        logger.error("AWS SNS error: %s", error_code)
        raise RuntimeError(f"Failed to create SNS subscription: {error_code}") from e


def list_subscriptions() -> list:
    """
    List current subscriptions for the configured topic.
    """
    if not validate_topic_arn(TOPIC_ARN):
        logger.error("Invalid or missing SNS_TOPIC_ARN configuration.")
        return []

    try:
        sns_client = boto3.client("sns")
        subscriptions = []
        paginator = sns_client.get_paginator("list_subscriptions_by_topic")

        for page in paginator.paginate(TopicArn=TOPIC_ARN):
            for sub in page.get("Subscriptions", []):
                subscriptions.append({
                    "subscription_arn": sub.get("SubscriptionArn"),
                    "protocol": sub.get("Protocol"),
                    "endpoint": sub.get("Endpoint"),
                })

        return subscriptions

    except ClientError as e:
        logger.error("Failed to list subscriptions: %s", e.response["Error"]["Code"])
        return []


